"""Derived ids for v2 entities.

`process_id` and `epoch_id` are stable hashes of identity composites. They
are computed at query time, not stored — same logs in, same ids out. See
docs/design/api.md for the algorithm and id semantics.

Hash form: ``sha256(f"{a}|{b}|...".encode()).hexdigest()[:16]``. The 16-char
prefix is opaque to clients; the natural identity composite stays on every
response so clients never need to reverse the hash.
"""

import hashlib


def derive_process_id(
    *,
    source_system: str,
    pid: int,
    cwd: str,
    earliest_received_at: float,
) -> str:
    """Hash of (source_system, pid, cwd, floor(earliest_received_at)).

    Floored to integer seconds so subsecond drift in the earliest hook's
    received_at doesn't perturb the id. PID reuse later still produces a
    different id because the new instance's earliest second differs.
    """
    key = f"{source_system}|{pid}|{cwd}|{int(earliest_received_at)}"
    return hashlib.sha256(key.encode()).hexdigest()[:16]


def derive_epoch_id(
    *,
    session_id: str,
    pid: int,
    source_system: str,
    cwd: str,
    earliest_received_at: float,
) -> str:
    """Hash of (session_id, pid, source_system, cwd, floor(earliest_received_at)).

    One epoch per (session_id, pid) span. A resume into a new pid produces a
    new epoch_id — the new pid changes the hash regardless of the timestamp.
    """
    key = f"{session_id}|{pid}|{source_system}|{cwd}|{int(earliest_received_at)}"
    return hashlib.sha256(key.encode()).hexdigest()[:16]
